    CONSTRAINT "FK_TravelFiles_Customers_PayerId" FOREIGN KEY ("PayerId") REFERENCES "Customers" ("Id") ON DELETE RESTRICT
);

CREATE TABLE "TariffValidities" (
    "Id" integer GENERATED BY DEFAULT AS IDENTITY,
    "StartDate" timestamp with time zone NOT NULL,
    "EndDate" timestamp with time zone NOT NULL,
    "Price" numeric(12,2) NOT NULL,
    "IsActive" boolean NOT NULL,
    "Notes" character varying(500),
    "CreatedAt" timestamp with time zone NOT NULL,
    "TariffId" integer NOT NULL,
    CONSTRAINT "PK_TariffValidities" PRIMARY KEY ("Id"),
    CONSTRAINT "FK_TariffValidities_Tariffs_TariffId" FOREIGN KEY ("TariffId") REFERENCES "Tariffs" ("Id") ON DELETE CASCADE
);

CREATE TABLE "AspNetUserClaims" (
    "Id" integer GENERATED BY DEFAULT AS IDENTITY,
    "UserId" text NOT NULL,
    "ClaimType" text,
    "ClaimValue" text,
    CONSTRAINT "PK_AspNetUserClaims" PRIMARY KEY ("Id"),
    CONSTRAINT "FK_AspNetUserClaims_AspNetUsers_UserId" FOREIGN KEY ("UserId") REFERENCES "AspNetUsers" ("Id") ON DELETE CASCADE
);

CREATE TABLE "AspNetUserLogins" (
    "LoginProvider" text NOT NULL,
